class Solution:
    def minimumOperations(self, nums, start, goal):
        """
        :type nums: List[int]
        :type start: int
        :type goal: int
        :rtype: int
        """
        if start == goal:
            return 0

        queue = deque([(start, 0)])
        visited = {start}

        while queue:
            x, ops = queue.popleft()

            for num in nums:
                # Three operations: +, -, ^
                for next_x in [x + num, x - num, x ^ num]:
                    if next_x == goal:
                        return ops + 1

                    # Only explore if in valid range
                    if next_x not in visited and 0 <= next_x <= 1000:
                        visited.add(next_x)
                        queue.append((next_x, ops + 1))

        return -1
